/*
 * 🌊【黄河】 - 简约优化的SillyTavern主题
 * 作者🖊️：黄河之水天上来
 * 发布📈：[Discord]类脑社区，旅程社区
 * 版本📌：plus 7.6
 * 时间📆：2026/1/18
 * 更新🔄：（1）qr优化（参考简约灰）（2）细节优化（3）全局变量优化（4）布局优化（5）输入框bug修复（6）topbar插件兼容
 * 允许⭕：[请务必注明来源]参考，授权二改
 * 禁止❌：[整体或任何部分]未授权未注明二改二传，未授权未注明转载，商用
 */

/* ====== 全局：字体修改 ====== */
@import url("字体链接");

body,
textArea,
pre,
code,
.edit_textarea {
    font-family: "字体名称" !important;
    font-weight: normal;
}

/* ====== 🌊【附加内容放置区】 ====== */
/* PS：附加的功能在这里 删除 或者 修改 */

/* 🌊 附加功能 */
:root {
    /* ▶ 正则 限宽 */
    /* （不需要时，删除，或者改为100%） */
    --regex_width: 85%;

    /* ▶ 气泡 毛玻璃 效果 */
    /* （越大越模糊，为0不模糊，推荐5px~10px） */
    --blur: 0px;

    /* ▶ 引用文本 高亮 */
    /* （越大越深，0%无高亮效果，建议设置为10~30%） */
    --opacity: 0%;

    /* ▶ 大代码块 内容限高 */
    /* （不需要时，删除，或者改为很大数） */
    --code_block_max_height: 240px;

    /* ▶ 推理块 内容限高 */
    /* （不需要时，删除，或者改为很大数） */
    --reasoning_max_height: 500px;

    /* ▶ QR栏（快捷回复） 内容限高 */
    /* （不需要时，删除，或者改为很大数） */
    --qr_max_height: 10em;
}

/* 🌊 消息文字 */
.mes_text p {
    /* ▶ 段落首行缩进 */
    /* （设置为2em，即可首行缩进两字符） */
    text-indent: 0em;

    /* ▶ 内行距 (行与行) */
    line-height: 1.6em;
    /* ▶ 外行距 (段与段) */
    margin-bottom: 1em;

    /* ▶ 字体加粗 */
    /* （越大越粗，常规400，粗体700） */
    font-weight: 400;
    /* ▶ 字体大小 */
    /* （越高越大，默认1em） */
    font-size: 1em;
}

/* 🌊 全局文字 */
:root {
    /* ▶ 全局文字加粗 */
    /* （默认为0不加粗，建议设为0~0.5） */
    -webkit-text-stroke-width: 0px !important;
}

/* ====== 特殊主题特有效果 ====== */
/* 【🩸红黑】用户阴影 */
/* div[is_user="true"] .mes_text * {
    text-shadow: 0 0 5px rgba(0, 0, 0, 0.8);
} */

/* 【Dark_微信】用户黑字 */
