}

.mes[is_user="true"] .mes_text q,
.mes[is_user="true"] .mes_text em {
    color: color-mix(in srgb, var(--yy) 50%, black);
} */

/* 【Light_消息】用户白字 */
/* div[is_user="true"] .mes_text p {
    color: white;
}

.mes[is_user="true"] .mes_block .ch_name,
.mes[is_user="true"] .mes_block .timestamp {
    color: white;
}

.mes[is_user="true"] .mes_text q,
.mes[is_user="true"] .mes_text em {
