} */

/* ====== 全局：变量 ====== */
:root {
    /* === 随动 === */
    --zw: var(--SmartThemeBodyColor);
    --xt: var(--SmartThemeEmColor);
    --xhx: var(--SmartThemeUnderlineColor);
    --yy: var(--SmartThemeQuoteColor);
    --yy2: var(--SmartThemeShadowColor);
    --bj: var(--SmartThemeChatTintColor);
    --ui: var(--SmartThemeBlurTintColor);
    --bk: var(--SmartThemeBorderColor);
    --user: var(--SmartThemeUserMesBlurTintColor);
    --char: var(--SmartThemeBotMesBlurTintColor);
    --zt: var(--mainFontSize);

    /* === 自定义 === */
    /* 滚动条宽度 */
    --gun_dong_tiao_width: 6px;
}

/* ====== 【☀️】 ====== */
:root {
    --ry0: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 120"><text x="60" y="70" font-size="75" fill="%23ffffff" text-anchor="middle" dominant-baseline="middle">☀️</text></svg>');
    --ry1: white;

    /* ●●●●【中间】●●●● */
    /* 阴影 */
    --shadow: color-mix(in srgb, var(--ui) 20%, black 10%);
    /* 主页面char背景 */
    --main_char_bei_jing: color-mix(in srgb, var(--ui) 40%, transparent);
    /* 推理块 */
    --reasoning: color-mix(in srgb, var(--ui) 70%, var(--yy) 30%);
    /* 滚动条 */
    --gun_dong_tiao: color-mix(in srgb, var(--ui) 70%, transparent);
    /* 大代码块 */
    --da_dai_ma_kuai_1: color-mix(in srgb, rgb(221, 221, 221) 10%, color-mix(in srgb, var(--zw) 80%, var(--ui) 20%) 90%);
    --da_dai_ma_kuai_2: color-mix(in srgb, var(--ui) 30%, white 55%);
    /* 引用块边框 */
    --ying_yong_kuai_bian_kuang: color-mix(in srgb, var(--yy) 50%, white);

    /* ▲▲▲▲【上方】▲▲▲▲ */
    /* 展开顶栏按钮 */
    --ui_an_niu: color-mix(in srgb, var(--ui) 20%, white 80%);
    /* 展开抽屉UI背景 */
    --ui_bei_jing: color-mix(in srgb, var(--ui_an_niu) 85%, transparent 1%);
    /* 滑动条 */
    --hua_dong_tiao: linear-gradient(135deg,
            color-mix(in srgb, var(--ui) 80%, var(--shu_ru_kuang)) 0%,
            color-mix(in srgb, var(--yy) 60%, white) 100%);
    /* 输入框 */
    --shu_ru_kuang: color-mix(in srgb, var(--ui) 5%, rgb(255, 255, 248) 95%);
    /* 标题栏 */
    --biao_ti_lan: linear-gradient(135deg,
            color-mix(in srgb, var(--shu_ru_kuang) 10%, var(--ui) 90%) 0% 20%,
            color-mix(in srgb, var(--yy) 20%, var(--ui) 80%) 45% 70%,
            color-mix(in srgb, var(--xhx) 30%, var(--ui) 70%) 95% 100%);
    /* 预设条目 */
    --yv_she_tiao_mu: color-mix(in srgb, var(--ui) 45%, var(--ry1) 20%);
    /* 正则条目 */
    --zheng_ze_tiao_mu: color-mix(in srgb, var(--ui) 70%, transparent);
    /* 用户设定 未选中 选中 */
    --user_she_ding_1: color-mix(in srgb, var(--ui) 60%, transparent);
    --user_she_ding_2: color-mix(in srgb, var(--ui) 100%, transparent);
    /* 勾选框 */
    --gou_xuan_kuang_1: color-mix(in srgb, var(--zw) 90%, transparent);
    --gou_xuan_kuang_2: var(--shu_ru_kuang);
    /* 按钮 */
    --an_niu_1: color-mix(in srgb, var(--ui) 30%, var(--shu_ru_kuang) 60%);
    --an_niu_2: color-mix(in srgb, var(--zw) 25%, transparent);
    /* 管理聊天文件背景 */
    --liao_tian_ji_lu: color-mix(in srgb, var(--ui) 20%, rgb(250, 250, 250) 80%);

    /* ▼▼▼▼【下方】▼▼▼▼ */
    /* 下菜单 */
    --xia_cai_dan: color-mix(in srgb, var(--ui) 60%, white 30%);
    /* 快捷回复 未选 选中 */
    --qr_1_1: color-mix(in srgb, var(--shu_ru_kuang) 80%, transparent);
    --qr_1_2: color-mix(in srgb, var(--zw) 70%, transparent);
    --qr_2_1: color-mix(in srgb, var(--da_dai_ma_kuai_1) 60%, transparent);
    --qr_2_2: white;
    --qr_3: color-mix(in srgb, var(--ui) 20%, var(--shu_ru_kuang) 50%);

    /* ………… 【附加】 ………… */
    /* 思维链 */
    --other_reasoning: linear-gradient(135deg,
            color-mix(in srgb, var(--xhx) 50%, var(--ui) 50%) 0% 20%,
            color-mix(in srgb, var(--yy) 30%, var(--ui) 70%) 45% 70%,
            var(--ui) 95% 100%);
}

/* ====== 【🌙】 ====== */
:root {
    --ry0: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 120"><text x="60" y="70" font-size="75" fill="%23ffffff" text-anchor="middle" dominant-baseline="middle">🌙</text></svg>');
    --ry1: black;

    /* ●●●●【中间】●●●● */
    /* 阴影 */
    --shadow: color-mix(in srgb, var(--yy) 15%, transparent);
    /* 主页面char背景 */
    --main_char_bei_jing: color-mix(in srgb, var(--yy) 20%, transparent);
    /* 推理块 */
    --reasoning: linear-gradient(135deg,
            color-mix(in srgb, var(--yy) 70%, var(--ui) 30%) 0%,
            color-mix(in srgb, var(--xhx) 70%, var(--ui) 30%) 100%);
    /* 滚动条 */
    --gun_dong_tiao: color-mix(in srgb, var(--yy) 50%, transparent);
    /* 大代码块 */
    --da_dai_ma_kuai_1: color-mix(in srgb, rgb(221, 221, 221) 15%, color-mix(in srgb, var(--yy) 20%, black 80%) 85%);
    --da_dai_ma_kuai_2: color-mix(in srgb, var(--yy) 40%, white 35%);
    /* 引用块边框 */
    --ying_yong_kuai_bian_kuang: color-mix(in srgb, var(--yy) 70%, black);

    /* ▲▲▲▲【上方】▲▲▲▲ */
    /* 展开顶栏按钮 */
    --ui_an_niu: color-mix(in srgb, var(--yy) 15%, var(--ui) 85%);
    /* 展开抽屉UI背景 */
    --ui_bei_jing: color-mix(in srgb, var(--ui_an_niu) 75%, transparent 1%);
    /* 滑动条 */
    --hua_dong_tiao: linear-gradient(135deg,
            var(--yy) 0%,
            var(--xhx) 100%);
    /* 输入框 */
    --shu_ru_kuang: color-mix(in srgb, black 50%, transparent);
    /* 标题栏 */
    --biao_ti_lan: linear-gradient(135deg,
            var(--ui) 0% 20%,
            color-mix(in srgb, var(--yy) 30%, var(--ui) 70%) 45% 70%,
            color-mix(in srgb, var(--xhx) 50%, var(--ui) 50%) 95% 100%);
    /* 预设条目 */
    --yv_she_tiao_mu: color-mix(in srgb, var(--yy) 20%, transparent);
    /* 正则条目 */
    --zheng_ze_tiao_mu: color-mix(in srgb, var(--yy) 20%, transparent);
    /* 用户设定 未选中 选中 */
    --user_she_ding_1: color-mix(in srgb, var(--yy) 15%, transparent);
    --user_she_ding_2: color-mix(in srgb, var(--yy) 25%, transparent);
    /* 勾选框 */
    --gou_xuan_kuang_1: var(--shu_ru_kuang);
    --gou_xuan_kuang_2: var(--yy);
    /* 按钮 */
    --an_niu_1: color-mix(in srgb, var(--shu_ru_kuang) 80%, var(--yy));
    --an_niu_2: color-mix(in srgb, var(--yy) 60%, transparent);
    /* 管理聊天文件背景 */
    --liao_tian_ji_lu: color-mix(in srgb, var(--yy) 20%, transparent);

    /* ▼▼▼▼【下方】▼▼▼▼ */
    /* 下菜单 */
    --xia_cai_dan: color-mix(in srgb, var(--yy) 20%, var(--ui) 60%);
    /* 快捷回复 未选 选中 */
    --qr_1_1: color-mix(in srgb, var(--da_dai_ma_kuai_1) 80%, transparent);
    --qr_1_2: color-mix(in srgb, var(--yy) 60%, white 30%);
    --qr_2_1: color-mix(in srgb, var(--yy) 60%, rgb(76, 76, 76) 20%);
    --qr_2_2: white;
    --qr_3: color-mix(in srgb, var(--ui) 20%, var(--shu_ru_kuang) 40%);

    /* ………… 【附加】 ………… */
    /* 思维链 */
    --other_reasoning: linear-gradient(135deg,
            color-mix(in srgb, var(--xhx) 50%, var(--ui) 50%) 0% 20%,
            color-mix(in srgb, var(--yy) 30%, var(--ui) 70%) 45% 70%,
            var(--ui) 95% 100%);
}

/* ====== 额外颜色定义 ====== */
:root {
    /* === 基础颜色 === */
    /* 输入框 */
    --black30a: var(--shu_ru_kuang);
    /* 其他阴影 */
    --black70a: color-mix(in srgb, var(--yy) 50%, transparent);

    /* === 预设颜色 === */
    /* 预设字体 */
    --white30a: color-mix(in srgb, var(--yy) 75%, white 20%);
    /* 预设图标+上字 */
    --white50a: var(--white30a);
}

/*
 * ●●●●●●●●●●●●●●●●●●●●●●
 * 🌊【中间区域】
 * ●●●●●●●●●●●●●●●●●●●●●●
 */

/* ====== 全局：布局调整 ====== */
/* 统一移除边框、阴影和圆角 */
#top-bar,
#sheld,
#chat,
#form_sheld {
    border: none !important;
    box-shadow: none !important;
    border-radius: 0px !important;
}

/* 顶部导航栏：固定高度，不压缩，无下间距 */
#top-bar {
    flex-shrink: 0;
    margin-bottom: 0 !important;
    z-index: 100;
}

/* 中间聊天区：自动填满剩余空间 */
#chat {
    /* 唯一需要伸缩填充空白的元素 */
    flex: 1;
    overflow-y: auto;
    margin-top: 0 !important;
    margin-bottom: 0 !important;
    height: auto !important;
}

/* 底部输入框：固定高度，不压缩，无上间距 */
#form_sheld {
    flex-shrink: 0;
    margin-top: 0 !important;
    width: 100%;
}

/* 
 * 去底部缝隙 
 * 来源：眠N勿扰（旅程）
 * 感谢这位老师的分享，解决了困扰我已久的底部缝隙
 */

#sheld {
    top: var(--bottomFormBlockSize);
    height: calc(100dvh - var(--bottomFormBlockSize));
    max-height: calc(100dvh - var(--bottomFormBlockSize));
}

/* ====== 文字样式优化 ====== */
/* 删除文本 */
del,
s {
    color: var(--xhx);
}

/* 高亮文本 */
mark {
    background-color: color-mix(in srgb, var(--yy) 60%, transparent);
    color: white;
    border-radius: 0px !important;
    padding: 0px 0.2em;
}

/* 引用文本 */
q {
    background-color: color-mix(in srgb, var(--yy) var(--opacity), transparent);
    border-radius: 3px;
}

/* ====== 头像优化 ====== */
.avatar img,
big-avatars .avatar img {
    border: none;
    box-shadow:
        0 0 0 2px var(--bk),
        0 0 20px 2px var(--shadow);
}

/* ====== 滚动条 ====== */
::-webkit-scrollbar {
    width: var(--gun_dong_tiao_width) !important;
}

::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
    background-color: var(--gun_dong_tiao);
    border: none !important;
    box-shadow: inset 0 0 0 1.2px var(--bk) !important;
}

/* 滚动条轨道 */
::-webkit-scrollbar-track {
    background-color: transparent;
}

/* ====== 编辑修改框（正文+推理块） ====== */
.edit_textarea,
.mes_reasoning_details textarea {
    background-color: color-mix(in srgb, var(--ry1) 40%, transparent);
    color: color-mix(in srgb, var(--zw) 80%, transparent);
    border: 2px solid color-mix(in srgb, var(--zw) 40%, transparent);
}

/* ====== 模糊气泡 ====== */
.no-blur .mes {
    -webkit-backdrop-filter: blur(var(--blur)) !important;
    backdrop-filter: blur(var(--blur)) !important;
}

/* ====== 引用块 ====== */
.mes_text blockquote {
    border: 1.3px solid var(--ying_yong_kuai_bian_kuang);
    border-left: 3.5px solid var(--yy);
    border-radius: 10px 0px 0px 0px;
    padding-right: 8px;
    background-color: color-mix(in srgb, var(--yy) 8%, transparent);
}

/* 引用块加下边距 */
.mes_text blockquote {
    margin-bottom: 15px;
}

/* ====== 代码块 ====== */
/* 大代码块 - 覆盖.hljs的背景颜色和文字颜色 */
.hljs {
    background-color: transparent !important;
    color: inherit;
}

/* 大代码块 - 颜色配置 */
pre {
    font-family: monospace;
    background-color: var(--da_dai_ma_kuai_1);
    color: var(--da_dai_ma_kuai_2);
    padding: 6px;
    border-radius: 10px;
}

code.hljs {
    border: none;
    border: 1.2px solid var(--da_dai_ma_kuai_2);
    border-radius: 7px;
    background-color: transparent !important;
}

/* 复制图标 */
.code-copy {
    color: color-mix(in srgb, var(--da_dai_ma_kuai_2) 80%, transparent) !important;
}

/* 阴影继承 */
pre * {
    text-shadow: inherit;
}

/* 小代码块 */
code {
    color: white;
    background-color: color-mix(in srgb, var(--yy) 60%, transparent);
    border-radius: 5px;
}

/* ====== 大代码块限高 ====== */
/* 代码块滚动条 */
.mes_text pre:has(code) {
    /* 限高 */
    max-height: var(--code_block_max_height);
    overflow-y: auto;
}

/* 滚动条轨道 */
.mes_text pre:has(code)::-webkit-scrollbar-track {
    border-radius: 0 10px 10px 0;
    background-color: rgba(255, 255, 255, 0.1);
}

/* ====== 推理块 think ====== */
/* 推理块 - 头部美化 */
.mes_reasoning_header {
    background: var(--reasoning);
    border: 2px solid var(--bk);
    border-radius: 8px !important;
    color: white;
    font-weight: bold;
    font-size: 1em;
    font-weight: 900;
    align-items: center !important;
}

/* 思考气泡 */
.mes_reasoning_header_title::before {
    content: "\f4ad";
    font-weight: 900;
    color: #ffffff;
    margin-right: 0.5em;
    display: inline-block;
    vertical-align: middle !important;
    font-family: "Font Awesome 6 Free", "Font Awesome 5 Free", sans-serif;
}

/* 小三角加粗 */
.mes_reasoning_arrow {
    -webkit-text-stroke: 0.12em currentColor;
}

/* 内部文字 */
.mes_reasoning {
    border-left: 3.5px solid color-mix(in srgb, var(--yy) 60%, transparent);
    border-radius: 5px 0 0 5px;
    max-height: var(--reasoning_max_height);
    overflow-y: auto;
}

/* ====== 开始页面char ====== */
.recentChat {
    background-color: var(--main_char_bei_jing) !important;
    margin: 0.25em 0 !important;
    border-radius: 5px !important;
}

/*
 * ▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲
 * 🌊【上方区域】
 * ▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲▲
 */

/* ▲▲▲ 【0 其他/总】 ▲▲▲ */

/* ====== 顶栏调整 ====== */
/* 顶栏灵活 */
.drawer-icon {
    font-size: calc(var(--mainFontSize) + 5px);
    /* 确保图标垂直居中 */
    display: flex;
    align-items: center;
    justify-content: center;
}

/* 顶栏选中 */
#top-settings-holder .drawer:has(.openDrawer) {
    background: var(--ui_an_niu);
}

/* 顶栏缝隙 */
#top-settings-holder {
    top: 0px !important;
    background-color: var(--ui) !important;
}

/* ====== 展开页面调整 ====== */
/* blur效果 */
.no-blur .drawer-content {
    backdrop-filter: blur(4px) !important;
    -webkit-backdrop-filter: blur(4px) !important;
}

#character_popup {
    backdrop-filter: blur(4px) !important;
}

/* 改变展开面板描边与去圆角 */
#left-nav-panel,
#right-nav-panel,
#character_popup,
#dialogue_popup,
.drawer-content,
#cfgConfig,
#floatingPrompt,
#completion_prompt_manager_popup {
    /* 背景抽屉颜色 */
    background: var(--ui_bei_jing) !important;

    /* 去圆角 */
    border-radius: 0 0 5px 5px;

    /* 改描边 */
    border: none !important;
    border-bottom: 1.7px solid var(--bk) !important;
    box-shadow: 0 5px 15px var(--shadow) !important;
}

/* 顶栏下划线 */
#top-settings-holder {
    border-bottom: 2.8px solid var(--bk);
    box-shadow: none !important;
}

/* 顶栏下阴影 */
#top-bar {
    box-shadow: none !important;
    box-shadow: 0 0px 30px 3px var(--shadow) !important;
}

/* ====== 滑动条 ====== */
/* 滑块emoji按钮样式 */
input[type="range"]::-webkit-slider-thumb {
    width: 28px;
    height: 28px;
    background: var(--ry0) no-repeat center center;
    background-size: contain;
    border: none;
}

/* 滑动条 */
input[type="range"] {
