/* 
 * 下为QR收纳代码
 * 参考：简约灰（Sanqian）
 * 感谢这个老师的开源代码，非常舒服的QR收纳设计，很有参考价值
 * 在此基础上，做了一些个人偏好的改动
 */

/* 初始时隐藏 QR 栏 */
#qr--bar {
    max-height: 0px;
    /* 隐藏超出内容 */
    overflow-y: hidden;
    /* 定位方式 */
    position: absolute !important;
    bottom: 100%;
    left: 0;
    right: 0;
    z-index: 0;
}

/* 鼠标悬停或获得焦点时，只有有按钮才展开 */
#send_form:has(#send_textarea:hover) #qr--bar:has(.qr--button),
#send_form:has(#send_textarea:focus-within) #qr--bar:has(.qr--button),
#qr--bar:has(.qr--button):hover {
    max-height: var(--qr_max_height);
    z-index: 100;
    overflow-y: auto;
    overflow-y: overlay;
    border-bottom: 2px solid var(--bk);
    border-top: 1.2px solid var(--bk);
}

/* 悬停或点击发送消息/停止发送按钮时，自动收回 QR 栏 */
#send_form:has(#send_but:hover) #qr--bar,
#send_form:has(#send_but:active) #qr--bar,
#send_form:has(#mes_stop:hover) #qr--bar,
#send_form:has(#mes_stop:active) #qr--bar {
    max-height: 0px;
    border: none;
    padding: 0;
    overflow: hidden;
}

/* 相对定位 */
#send_form {
    position: relative;
}

