/*
 * ■□■□■□■□■□■□■□■□■□■□■□■□
 * 🌊【黄河】- 布局优化
 * 版本：2.4
 * 日期：2026/1/19
 * 更改：宽度适配
 */

/* ====== 聊天界面布局 ====== */
:root {
    /* 左右宽度 */
    --width: 20px;
}

/* 最外层聊天气泡 */
#chat {
    overflow-y: scroll;
    align-items: center;
    /* 上右下左 */
    padding: 9px calc(var(--width) - var(--gun_dong_tiao_width)) 30px var(--width) !important;
}

/* 聊天气泡间距调整 */
body.bubblechat .mes {
    /* 上下 */
    margin-bottom: 9px;
}

/* 针对 Apple 设备的额外修复 */
@supports (-webkit-touch-callout: none) {
    #chat {
        padding-right: var(--width) !important;
    }
}

/* 内部文本 */
.mes_text {
    /* ▶ 气泡内部内容 */
    padding: 0.5em 0.2em 10px 0.3em;
    text-align: left;
}

/* 气泡内部 */
.mes_block {
    width: 100%;
    padding: 15px 0.5em 0 0.5em;
}

/* 整体最外 */
.mes {
    width: 100%;
    flex-direction: column;
    align-items: center;
    margin: 0 auto;
    border-radius: 15px !important;
}

/* ====== reasoning左边距 ====== */
.mes_reasoning_details {
    padding-left: 0.3em;
}

/* ====== 最后一条消息调整 ====== */
/* 最后一条消息：滑动箭头 */
div[is_user='false'].last_mes .mes_block {
    padding-bottom: 50px !important;
}

/* 最后一条消息：头像边距 */
.last_mes .mesAvatarWrapper {
    padding-bottom: 0;
}

/* 最后一条消息：底部 */
.mes[is_user="false"].last_mes {
    padding-bottom: 0;
}

/*
 * ★☆★☆★☆★☆★☆★☆★☆★☆★☆★☆★☆★☆
 * 🌊【布局】 - 消息首部
 * 参考：双色盒子（kakaa）
 * 样式：① 居中+分割线
 * 日期：2026/1/3
 */

/* 楼层、时间和token计数器并排显示 */
.mesIDDisplay,
.mes_timer,
.tokenCounterDisplay {
    display: contents;
    color: rgba(140, 140, 140, 1);
    font-size: 0.75em;
}

/* 头像包装器布局 */
.mesAvatarWrapper {
    margin: 0 auto;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding-bottom: 0;
}

/* 头像与其容器的间距关系 */
.mesAvatarWrapper .avatar {
    margin: 0.4em 0 0.2em 0;
}

/* 名称 */
#chat .ch_name {
    position: relative;
    align-items: flex-end;
    padding-bottom: 0.7em !important;
    padding-left: 0.3em;
    font-size: 1.1em;
}

/* 分割线 */
#chat .ch_name::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 1.5px;
    /* 渐变 */
    background: linear-gradient(to right,
            transparent 0%,
            color-mix(in srgb, var(--zw) 40%, transparent) 10%,
            color-mix(in srgb, var(--zw) 40%, transparent) 90%,
            transparent 100%);
}

/* ====== 布局重构：头像上置 & 气泡调整 ====== */

/* 主容器设置为相对定位，为绝对定位的元素（时间等）提供基准 */
.mes {
    position: relative !important;
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    margin-top: 120px !important;
    overflow: visible !important;
}

/* 头像包装器：使用 order 属性将其排在最前（上方） */
.mesAvatarWrapper {
    order: -1 !important;
    /* 头像与下方气泡的间距 */
    margin: 0 auto 5px auto !important;
    width: auto !important;
    /* 绝对定位到气泡正上方 */
    position: absolute !important;
    /* 根据头像大小调整这个负值 */
    top: -100px;
    left: 50%;
    /* 居中 */
